#!/usr/bin/env node
import { createHash } from "node:crypto";
import * as fs from "node:fs";
import * as path from "node:path";
const [mode, stateArg, engagementArg, ...files] = process.argv.slice(2);
if (!['shadow','draft'].includes(mode) || !stateArg || !engagementArg) throw new Error("usage: record-pilot-metrics.mjs <shadow|draft> STATE_DIR ENGAGEMENT_ID INPUT...");
if (!/^[A-Za-z0-9][A-Za-z0-9._-]{0,127}$/.test(engagementArg)) throw new Error("unsafe engagement identity");
const state = fs.realpathSync(stateArg); const engagement = path.join(state, "engagements", engagementArg); const metrics = path.join(engagement, "metrics");
if (!fs.realpathSync(engagement).startsWith(`${state}${path.sep}`)) throw new Error("engagement path escapes state root");
const read = (file) => JSON.parse(fs.readFileSync(file, "utf8")); const q = (value, quality, unit) => ({ value, quality, unit });
const stable = (v) => Array.isArray(v) ? `[${v.map(stable).join(',')}]` : v && typeof v === 'object' ? `{${Object.keys(v).sort().map((k)=>`${JSON.stringify(k)}:${stable(v[k])}`).join(',')}}` : JSON.stringify(v);
function append(stream, raw) { const event = { ...raw, event_id: createHash("sha256").update(stable(raw)).digest("hex") }; fs.mkdirSync(metrics, { recursive: true, mode: 0o700 }); const target = path.join(metrics, `${stream}-events.jsonl`); const current = fs.existsSync(target) ? fs.readFileSync(target, "utf8") : ""; if (current && !current.endsWith("\n")) throw new Error(`corrupt metric JSONL: ${target}`); const records = current.split("\n").filter(Boolean).map((line) => JSON.parse(line)); if (records.some((item) => item.event_id === event.event_id)) return; const fd = fs.openSync(target, "a", 0o600); try { fs.writeSync(fd, `${JSON.stringify(event)}\n`); fs.fsyncSync(fd); } finally { fs.closeSync(fd); } }
const common = (type, runId, timestamp, workflowId, source, evidence, quality, method, payload) => ({ schema_version: "1", event_type: type, engagement_id: engagementArg, workflow_id: workflowId, run_id: runId, timestamp, source, execution_origin: mode === 'shadow' ? 'github_live_shadow' : 'github_draft', provenance: { quality, method, source_reference: evidence[0] ?? null }, evidence_references: evidence, redaction_status: "reference_only", payload });
if (mode === 'shadow') {
  const packet = read(files[0]); if (packet.engagement_id !== engagementArg) throw new Error("shadow engagement identity mismatch"); const run = packet.eval.run_id, workflow = packet.current_workflow_context.workflow_id, refs = [`shadow/${run}/evidence-packet.json`];
  append('run', common('run_started', run, packet.attestation.started_at, workflow, 'runtime', refs, 'measured', 'GitHub Actions runner clock and identity', { mode:'shadow', issue:String(packet.issue.number), repository:packet.repository.github_repository, commit:packet.repository.commit_sha, engagement:engagementArg, start_time:packet.attestation.started_at }));
  append('run', common('readiness_recorded', run, packet.attestation.ended_at, workflow, 'evaluation', refs, 'derived', 'deterministic shadow readiness checks', { readiness:packet.readiness.status, missing_information:packet.uncertainties, escalations:packet.escalations, evidence_references:refs }));
  append('run', common('plan_recorded', run, packet.attestation.ended_at, workflow, 'runtime', refs, 'measured', 'shadow packet structured fields and runner clock', { time_to_first_plan_ms:q(packet.runtime.milliseconds,'measured','ms'), candidate_file_count:q(packet.candidate_files.length,'measured','count'), proposed_test_count:q(packet.proposed_tests.length,'measured','count'), risk_count:q(packet.risks.length,'measured','count'), human_escalation_required:packet.escalations.length>0 }));
  append('run', common('run_completed', run, packet.attestation.ended_at, workflow, 'runtime', refs, 'measured', 'shadow runner and structured graders', { final_status:packet.eval.results.every((r)=>r.passed)?'completed':'failed', runtime_ms:q(packet.runtime.milliseconds,'measured','ms'), cost_accounting_status:'measured', measured_cost_usd:q(packet.cost.amount_usd,'measured','usd'), estimated_cost_usd:q(null,'unavailable','usd'), reserved_exposure_usd:q(null,'unavailable','usd'), model_call_count:q(0,'measured','count'), tool_call_count:q(null,'unavailable','count'), retry_count:q(0,'measured','count'), timeout:packet.failure_categories.includes('timeout'), cancellation:false, safety_status:packet.eval.classification==='invalid_live_shadow_evidence'?'failed':'passed', validation_status:packet.eval.results.every((r)=>r.passed)?'passed':'failed' }));
} else {
  const gate=read(files[0]), validation=read(files[1]), runState=read(files[2]); if (gate.engagement_id!==engagementArg) throw new Error("draft engagement identity mismatch"); const run=`draft-${process.env.GITHUB_RUN_ID ?? gate.base_commit.slice(0,12)}-${process.env.GITHUB_RUN_ATTEMPT ?? '1'}`, workflow=gate.workflow_id ?? 'draft', refs=['draft-validation.json','draft-run-state.json']; const started=runState.runtime.started_at, ended=new Date(Date.parse(started)+validation.runtime_ms).toISOString(); const calls=Array.isArray(validation.model_calls)?validation.model_calls:[];
  append('run', common('run_started',run,started,workflow,'runtime',refs,'measured','draft admission and runner identity',{mode:'draft',issue:String(gate.issue_number),repository:process.env.GITHUB_REPOSITORY ?? 'unavailable',commit:gate.base_commit,engagement:engagementArg,start_time:started}));
  append('run', common('run_completed',run,ended,workflow,'runtime',refs,'measured','hardened draft run-control and validation',{final_status:validation.publication_allowed?'completed':runState.runtime.cancellation_requested_at?'cancelled':'failed',runtime_ms:q(validation.runtime_ms,'measured','ms'),cost_accounting_status:validation.cost_measurement_status,measured_cost_usd:q(validation.measured_cost_usd,validation.measured_cost_usd===null?'unavailable':'measured','usd'),estimated_cost_usd:q(validation.estimated_cost_usd,validation.estimated_cost_usd===null?'unavailable':'estimated','usd'),reserved_exposure_usd:q(validation.reserved_cost_usd,validation.reserved_cost_usd===null?'unavailable':'estimated','usd'),model_call_count:q(calls.length,'measured','count'),tool_call_count:q(null,'unavailable','count'),retry_count:q(validation.retries ?? 0,'measured','count'),timeout:Boolean(runState.runtime.deadline_exceeded_at),cancellation:Boolean(runState.runtime.cancellation_requested_at),safety_status:validation.diff_policy?.safety===false?'failed':'passed',validation_status:validation.passed?'passed':'failed'}));
  if (runState.publication?.pr_number) append('run',common('draft_published',run,ended,workflow,'github',['draft-run-state.json'],'measured','GitHub publication recovery state',{pr_number:runState.publication.pr_number,pr_url:runState.publication.pr_url,branch:runState.publication.branch,publication:runState.publication.recovered?'recovered':'newly_created',time_to_draft_ms:q(validation.runtime_ms,'measured','ms'),validation_status:validation.passed?'passed':'failed_allowed'}));
}
